  51→function filterSections(sections: SectionData[], query: string): SectionData[] {
  52→  if (!query) return sections;
  53→  const lower = query.toLowerCase();
  54→  return sections
  55→    .map(section => ({
  56→      ...section,
  57→      items: section.items.filter(
  58→        item =>
  59→          item.title.toLowerCase().includes(lower) ||
  60→          item.subtitle?.toLowerCase().includes(lower),
  61→      ),
  62→    }))
  63→    .filter(section => section.items.length > 0);
  64→}
  65→
  66→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
  67→  if (!query) return colors;
  68→  const lower = query.toLowerCase();
  69→  return colors.filter(
  70→    c =>
  71→      c.title.toLowerCase().includes(lower) ||
  72→      c.subtitle?.toLowerCase().includes(lower),
  73→  );
  74→}
  75→
  76→function flattenItems(sections: SectionData[]): ListItemData[] {
  77→  return sections.flatMap(s => s.items);
  78→}
  79→
  80→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
  81→  switch (entry.type) {
  82→    case 'label':
  83→      return (
  84→        <DetailMetadata.Label
  85→          key={index}
  86→          title={entry.title}
  87→          text={entry.text}
  88→        />
  89→      );
  90→    case 'link':
  91→      return (
  92→        <DetailMetadata.Link
  93→          key={index}
  94→          title={entry.title}
  95→          text={entry.text}
  96→          target={entry.target}
  97→        />
  98→      );
  99→    case 'tag-list':
 100→      return (
 101→        <DetailMetadata.TagList key={index} title={entry.title}>
 102→          {entry.tags.map(tag => (
 103→            <DetailMetadata.Tag
 104→              key={tag.text}
 105→              text={tag.text}
 106→              color={tag.color}
 107→            />
 108→          ))}
 109→        </DetailMetadata.TagList>
 110→      );
 111→    case 'separator':
 112→      return <DetailMetadata.Separator key={index} />;
 113→  }
 114→}
